mapper.select:
SELECT A.REQUEST_KEY , A.RES_NO , A.CNTPNT_SHOP_ID , FN_GET_ORGNM(A.CNTPNT_SHOP_ID) AS AGENT_NAME , A.REQ_BUY_TYPE , FN_GET_CODENM('RCP9004', A.REQ_BUY_TYPE) AS REQ_BUY_NM , A.OPER_TYPE , FN_GET_CODENM('RCP9001', A.OPER_TYPE) AS OPER_NAME , A.REQUEST_STATE_CODE , FN_GET_CODENM('RCP0006', A.REQUEST_STATE_CODE) REQUEST_STATE_NAME , A.SERVICE_TYPE , FN_GET_CODENM('RCP0013', A.SERVICE_TYPE) AS SERVICE_NAME , TO_CHAR(A.REQ_IN_DAY, 'YYYY-MM-DD') REQ_IN_DT , A.ON_OFF_TYPE , FN_GET_CODENM('RCP0007', NVL(A.ON_OFF_TYPE, '0')) ON_OFF_NM , A.OPEN_MARKET_REFERER , MDL.MNFCT_ID , DECODE(A.REQ_BUY_TYPE, 'MM', ( SELECT MNFCT_NM FROM ORG_MNFCT_MST WHERE MNFCT_ID = MDL.MNFCT_ID ), '') AS MNFCT_NM , DECODE(A.REQ_BUY_TYPE, 'MM', MDL.RPRS_PRDT_ID, '') AS PRDT_ID , DECODE(A.REQ_BUY_TYPE, 'MM', MDL.PRDT_CODE, '') AS PRDT_CODE , DECODE(A.REQ_BUY_TYPE, 'MM', MDL.PRDT_NM, '') AS MODEL_NAME , DECODE(A.REQ_BUY_TYPE, 'MM', NVL(FN_GET_CODENM ('CMN0044', MDL.PRDT_COLR_CD), A.REQ_MODEL_COLOR), '') AS REQ_MODEL_COLOR , A.REQ_PHONE_SN , ( SELECT MNFCT_NM FROM ORG_MNFCT_MST WHERE MNFCT_ID = USIM.MNFCT_ID ) AS USIM_MNFCT_NM , USIM.PRDT_CODE AS USIM_ID , USIM.PRDT_NM AS USIM_NAME , A.REQ_USIM_SN , A.SPC_CODE , A.MEMO AS REQUEST_MEMO , C.SOC_CODE , FN_GET_RATENM(C.SOC_CODE) AS SOC_NAME , A.CSTMR_TYPE , B.CSTMR_NAME , B.CSTMR_NAME AS CSTMR_NAME2 , B.CSTMR_NATIVE_RRN , B.CSTMR_FOREIGNER_RRN , B.CSTMR_PRIVATE_CNAME , B.CSTMR_PRIVATE_NUMBER , B.CSTMR_JURIDICAL_CNAME , B.CSTMR_JURIDICAL_RRN , SUBSTR(REPLACE(CRYPTO_AES256.DEC_AES(DECODE(A.CSTMR_TYPE, 'FN', TRIM(B.CSTMR_FOREIGNER_RRN), TRIM(B.CSTMR_NATIVE_RRN))), '-', ''), 0, 6) as BIRTH_DT /* 생년월일추가 */ , SUBSTR(REPLACE(CRYPTO_AES256.DEC_AES(DECODE(A.CSTMR_TYPE, 'FN', TRIM(B.CSTMR_FOREIGNER_RRN), TRIM(B.CSTMR_NATIVE_RRN))), '-', ''), 7, 1) as GENDER /* 성별추가 */ , B.CSTMR_TEL_FN , B.CSTMR_TEL_MN , B.CSTMR_TEL_RN , B.CSTMR_TEL_FN || B.CSTMR_TEL_MN || B.CSTMR_TEL_RN AS CSTMR_TEL , B.CSTMR_MOBILE_FN , B.CSTMR_MOBILE_MN , B.CSTMR_MOBILE_RN , B.CSTMR_MOBILE_FN || B.CSTMR_MOBILE_MN || B.CSTMR_MOBILE_RN AS CSTMR_MOBILE , B.CSTMR_POST , B.CSTMR_ADDR , B.CSTMR_ADDR_DTL , B.CSTMR_MAIL , D.DLVRY_NAME , D.DLVRY_TEL_FN , D.DLVRY_TEL_MN , D.DLVRY_TEL_RN , D.DLVRY_MOBILE_FN , D.DLVRY_MOBILE_MN , D.DLVRY_MOBILE_RN , D.DLVRY_MOBILE_FN || D.DLVRY_MOBILE_MN || D.DLVRY_MOBILE_RN AS DLVRY_MOBILE , D.DLVRY_POST , D.DLVRY_ADDR , D.DLVRY_ADDR_DTL , D.DLVRY_ADDR || ' ' || D.DLVRY_ADDR_DTL AS FULL_DLVRY_ADDR , D.DLVRY_ADDR_BJD , D.DLVRY_MEMO , E.TB_CD , E.DLVRY_NO , CASE WHEN A.REQUEST_STATE_CODE IN ('08', '09', '10') THEN TO_CHAR(A.SYS_RDATE, 'YYYYMMDDHH24MISS') ELSE '' END DLV_DTTM , CASE WHEN A.REQUEST_STATE_CODE IN ('08', '09') THEN TO_CHAR(A.SYS_RDATE, 'HH24:MI:SS') ELSE '' END SET_DTTM , TO_CHAR(A.SYS_RDATE, 'YYYYMMDDHH24MISS') AS SYS_RDATE , FN_GET_USRNM(A.RVISN_ID) AS RVISN_NM , TO_CHAR(A.RVISN_DTTM, 'YYYY-MM-DD HH24:MI:SS') AS RVISN_DTTM , FN_GET_CODENM('RCP2035', A.USIM_KINDS_CD) AS USIM_KINDS_NM , A.PROD_NM AS DRCT_MNGM_PRDC_NM /* 직영상품명 */ FROM MCP_REQUEST@DL_MCP A , MCP_REQUEST_CSTMR@DL_MCP B , MCP_REQUEST_SALEINFO@DL_MCP C , MCP_REQUEST_DLVRY@DL_MCP D , MCP_REQUEST_STATE@DL_MCP E , CMN_INTM_MDL MDL , CMN_INTM_MDL USIM WHERE 1 = 1 AND A.REQUEST_KEY = B.REQUEST_KEY AND A.REQUEST_KEY = C.REQUEST_KEY AND A.REQUEST_KEY = D.REQUEST_KEY AND A.REQUEST_KEY = E.REQUEST_KEY AND C.MODEL_ID = MDL.PRDT_ID(+) AND A.REQ_USIM_NAME = USIM.PRDT_CODE(+) AND A.REQ_IN_DAY BETWEEN TO_DATE(#{strtDt} || '000000', 'YYYYMMDDHH24MISS') AND TO_DATE(#{endDt} || '235959', 'YYYYMMDDHH24MISS') AND A.PSTATE = '00' AND (A.USIM_KINDS_CD != '09' OR A.USIM_KINDS_CD IS NULL) AND A.CNTPNT_SHOP_ID = #{agntCd}
AND A.SERVICE_TYPE = #{serviceType}
AND A.REQUEST_STATE_CODE = #{requestStateCode}
AND A.REQ_BUY_TYPE = #{reqBuyType}
AND A.OPER_TYPE = #{pOperType} /*신청유형-신규가입/번호이동정보/기기변경정보*/
AND B.CSTMR_NAME LIKE #{searchVal} || '%'
AND A.CONTRACT_NUM = #{searchVal}
AND NVL(B.CSTMR_MOBILE_FN || B.CSTMR_MOBILE_MN || B.CSTMR_TEL_RN, B.CSTMR_TEL_FN || B.CSTMR_TEL_MN || B.CSTMR_MOBILE_RN) LIKE TRANSLATE(#{searchVal},'1234567890-','1234567890')||'%'
AND A.REQ_PHONE_SN LIKE '%' || #{searchVal} || '%'
AND A.RES_NO LIKE '%' || #{searchVal} || '%'
AND A.USIM_KINDS_CD = #{usimKindsCd}
ORDER BY A.REQUEST_KEY DESC
